import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  getSlotById, getAvailableSeats, bookSeats, processPayment,
  validateDiscountCode, getLoyaltyOffer,
} from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const PAYMENT_METHODS = ['UPI','CARD','NETBANKING','WALLET'];
const PM_ICONS  = { UPI: '­¤ō▒', CARD: '­¤Æ│', NETBANKING: '­¤Å”', WALLET: '­¤æø' };
const SEAT_COLOR = { VIP: '#c97d1a', PREMIUM: '#2563a8', REGULAR: '#6b7280' };

const BookingPage = () => {
  const { slotId } = useParams();
  const navigate   = useNavigate();
  const { user }   = useAuth();

  const [slot, setSlot]               = useState(null);
  const [seatSlots, setSeatSlots]     = useState([]);
  const [selected, setSelected]       = useState([]);
  const [loading, setLoading]         = useState(true);
  const [step, setStep]               = useState(1);
  const [payMethod, setPayMethod]     = useState('UPI');
  const [booking, setBooking]         = useState(null);
  const [processing, setProcessing]   = useState(false);

  // Discount state
  const [promoCode, setPromoCode]         = useState('');
  const [promoDiscount, setPromoDiscount] = useState(0);     // percent 0-1
  const [promoError, setPromoError]       = useState('');
  const [promoApplied, setPromoApplied]   = useState(false);
  const [validatingCode, setValidating]   = useState(false);

  // Loyalty state
  const [loyaltyDiscount, setLoyaltyDiscount] = useState(0); // percent 0-1
  const [loyaltyChecked, setLoyaltyChecked]   = useState(false);

  useEffect(() => {
    const load = async () => {
      try {
        const [slRes, seatsRes, loyaltyRes] = await Promise.all([
          getSlotById(slotId),
          getAvailableSeats(slotId),
          getLoyaltyOffer(user.userId),
        ]);
        setSlot(slRes.data?.data || null);
        setSeatSlots(Array.isArray(seatsRes.data?.data) ? seatsRes.data.data : []);
        const loyalty = loyaltyRes.data?.data;
        if (loyalty?.hasOffer) {
          setLoyaltyDiscount(loyalty.discountPercent);
          setLoyaltyChecked(true);
        }
      } catch (err) {
        toast.error('Failed to load booking details');
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [slotId, user.userId]);

  const toggleSeat = (ss) => {
    const already = selected.find((s) => s.seatSlotId === ss.seatSlotId);
    if (already) {
      setSelected((prev) => prev.filter((s) => s.seatSlotId !== ss.seatSlotId));
    } else {
      if (selected.length >= 10) { toast.error('Max 10 seats per booking'); return; }
      setSelected((prev) => [...prev, ss]);
    }
  };

  const subtotal = selected.reduce((sum, ss) => sum + parseFloat(ss.price || 0), 0);

  // Best discount wins (loyalty vs promo code)
  const effectiveDiscountPct = Math.max(loyaltyDiscount, promoDiscount);
  const discountAmt   = parseFloat((subtotal * effectiveDiscountPct).toFixed(2));
  const total         = Math.max(0, subtotal - discountAmt);
  const isLoyaltyUsed = loyaltyDiscount > 0 && loyaltyDiscount >= promoDiscount;

  const handleValidateCode = async () => {
    if (!promoCode.trim()) return;
    setValidating(true);
    setPromoError('');
    try {
      const res  = await validateDiscountCode(promoCode.trim());
      const data = res.data;
      if (!data.success) {
        setPromoError('Invalid discount code. Please check and try again.');
        setPromoDiscount(0);
        setPromoApplied(false);
      } else {
        const pct = data.data.discountPercent;
        setPromoDiscount(pct);
        setPromoApplied(true);
        toast.success(`Code applied! ${Math.round(pct * 100)}% off`);
      }
    } catch {
      setPromoError('Invalid discount code.');
      setPromoDiscount(0);
      setPromoApplied(false);
    } finally {
      setValidating(false);
    }
  };

  const handleConfirmBooking = async () => {
    if (selected.length === 0) { toast.error('Please select at least one seat'); return; }
    setProcessing(true);
    try {
      const bookRes = await bookSeats({
        userId:        user.userId,
        slotId:        parseInt(slotId),
        seatIds:       selected.map((s) => s.seat?.seatId).filter(Boolean),
        discount:      discountAmt,
        paymentMethod: payMethod,
        discountCode:  promoApplied && promoDiscount >= loyaltyDiscount ? promoCode.toUpperCase() : null,
      });
      const reservation = bookRes.data?.data;
      if (!reservation?.reservationId) throw new Error('Reservation failed');

      const txnRes = await processPayment({
        reservationId:  reservation.reservationId,
        paymentMethod:  payMethod,
        amount:         total,
        discountAmount: discountAmt,
        transactionRef: null,
      });
      const transaction = txnRes.data?.data;

      setBooking({ reservation, transaction });
      setStep(3);
      toast.success('­¤Äē Booking confirmed!');
    } catch (err) {
      toast.error(err.response?.data?.message || err.message || 'Booking failed');
    } finally {
      setProcessing(false);
    }
  };

  if (loading) return <div className="loading-center"><div className="spinner" /><span>Loading seats...</span></div>;
  if (!slot)   return (
    <div className="empty-state" style={{ marginTop: '80px' }}>
      <div className="empty-state-icon">ŌØī</div><h3>Show not found</h3>
      <button onClick={() => navigate(-1)} className="btn btn-secondary" style={{ marginTop: '16px' }}>Go Back</button>
    </div>
  );

  const availableSeats = seatSlots.filter((ss) => ss.availability === 'AVAILABLE');
  const rows = {};
  availableSeats.forEach((ss) => {
    const r = ss.seat?.rowLetter || '?';
    if (!rows[r]) rows[r] = [];
    rows[r].push(ss);
  });

  return (
    <div style={{ background: 'var(--bg-secondary)', minHeight: '100vh' }}>
      <div className="container" style={{ maxWidth: '960px', paddingTop: '32px', paddingBottom: '60px' }}>

        <button onClick={() => step > 1 ? setStep(step - 1) : navigate(-1)}
          className="btn btn-ghost btn-sm" style={{ marginBottom: '20px', paddingLeft: 0 }}>
          ŌåÉ {step > 1 ? 'Back' : 'Back to Event'}
        </button>

        {/* Progress */}
        <div style={{ display: 'flex', marginBottom: '28px', background: 'var(--bg-card)', borderRadius: '12px', border: '1.5px solid var(--border)', overflow: 'hidden' }}>
          {[['1','Select Seats'],['2','Payment'],['3','Confirmed']].map(([num, label], i) => {
            const sn = i + 1;
            const isActive   = step === sn;
            const isComplete = step > sn;
            return (
              <div key={num} style={{ flex: 1, padding: '12px 16px', display: 'flex', alignItems: 'center', gap: '8px',
                background: isActive ? 'var(--accent-dim)' : isComplete ? '#f0faf6' : 'transparent',
                borderRight: i < 2 ? '1.5px solid var(--border)' : 'none' }}>
                <div style={{ width: 24, height: 24, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '12px', fontWeight: 700,
                  background: isActive ? 'var(--accent)' : isComplete ? 'var(--green)' : 'var(--border)',
                  color: isActive || isComplete ? 'white' : 'var(--text-muted)' }}>
                  {isComplete ? 'Ō£ō' : num}
                </div>
                <span style={{ fontSize: '13px', fontWeight: isActive ? 700 : 500,
                  color: isActive ? 'var(--accent)' : isComplete ? 'var(--green)' : 'var(--text-muted)' }}>
                  {label}
                </span>
              </div>
            );
          })}
        </div>

        {/* Slot info */}
        <div className="card" style={{ padding: '18px 24px', marginBottom: '24px' }}>
          <div style={{ display: 'flex', gap: '24px', flexWrap: 'wrap', alignItems: 'center' }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem', fontWeight: 400 }}>{slot.event?.name || 'Show'}</div>
              <div style={{ fontSize: '13px', color: 'var(--text-secondary)', marginTop: '5px', fontWeight: 500, display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                <span>­¤ōģ {slot.showDate}</span>
                <span>ŌÅ░ {slot.startTime?.slice(0,5)} ŌĆō {slot.endTime?.slice(0,5)}</span>
                {slot.location?.locName && <span>­¤ōŹ {slot.location.locName}</span>}
              </div>
            </div>
            <div style={{ textAlign: 'right' }}>
              <div style={{ fontSize: '11px', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.5px', fontWeight: 600 }}>Seats Available</div>
              <div style={{ fontFamily: 'var(--font-display)', fontSize: '2rem', fontWeight: 400, color: slot.seatsLeft > 20 ? 'var(--green)' : 'var(--gold)' }}>{slot.seatsLeft}</div>
            </div>
          </div>
        </div>

        {/* ŌöĆŌöĆ Step 3: Confirmation ŌöĆŌöĆ */}
        {step === 3 && booking && (
          <div style={{ maxWidth: '480px', margin: '0 auto', textAlign: 'center' }}>
            <div className="card" style={{ padding: '48px 40px', border: '2px solid var(--green)', boxShadow: '0 8px 32px rgba(26,143,99,0.12)' }}>
              <div style={{ fontSize: '64px', marginBottom: '16px' }}>­¤Äē</div>
              <h2 style={{ fontFamily: 'var(--font-display)', fontSize: '2.2rem', fontWeight: 400, color: 'var(--green)', marginBottom: '6px' }}>Booking Confirmed!</h2>
              <p style={{ color: 'var(--text-muted)', marginBottom: '28px', fontSize: '14px' }}>A confirmation email has been sent to {user.mail}</p>
              <div style={{ background: 'var(--bg-secondary)', borderRadius: '10px', padding: '18px', marginBottom: '24px', textAlign: 'left' }}>
                <InfoRow label="Ref Code"    value={booking.reservation?.refCode} mono />
                <InfoRow label="Amount Paid" value={`Ōé╣${parseFloat(booking.reservation?.amount || 0).toFixed(2)}`} />
                {booking.reservation?.discount > 0 && (
                  <InfoRow label="Discount" value={`-Ōé╣${parseFloat(booking.reservation.discount).toFixed(2)}`} />
                )}
                <InfoRow label="Payment"     value={booking.transaction?.paymentMethod} />
                <InfoRow label="Txn Ref"     value={booking.transaction?.transactionRef || 'N/A'} mono />
                <InfoRow label="Status"      value="Ō£ģ Confirmed" last />
              </div>
              <div style={{ display: 'flex', gap: '12px' }}>
                <button onClick={() => navigate('/my-bookings')} className="btn btn-primary" style={{ flex: 1 }}>My Bookings</button>
                <button onClick={() => navigate('/')} className="btn btn-secondary" style={{ flex: 1 }}>Browse More</button>
              </div>
            </div>
          </div>
        )}

        {/* ŌöĆŌöĆ Step 2: Payment ŌöĆŌöĆ */}
        {step === 2 && (
          <div style={{ maxWidth: '500px', margin: '0 auto' }}>

            {/* Loyalty offer banner */}
            {loyaltyChecked && loyaltyDiscount > 0 && (
              <div style={{ background: 'linear-gradient(135deg,#fff8f5,#fef2ea)', border: '2px dashed var(--accent)', borderRadius: '12px', padding: '16px 20px', marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '12px' }}>
                <div style={{ fontSize: '32px' }}>­¤ī¤</div>
                <div>
                  <div style={{ fontWeight: 700, color: 'var(--accent)', fontSize: '15px' }}>
                    Loyalty Offer Applied! {Math.round(loyaltyDiscount * 100)}% OFF
                  </div>
                  <div style={{ fontSize: '12px', color: 'var(--text-secondary)', marginTop: '2px' }}>
                    You earned this by making 5+ bookings this month. Automatically applied!
                  </div>
                </div>
              </div>
            )}

            {/* Order Summary */}
            <div className="card" style={{ padding: '28px', marginBottom: '16px' }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', fontWeight: 400, marginBottom: '20px' }}>Order Summary</h3>
              {selected.map((s) => (
                <div key={s.seatSlotId} style={{ display: 'flex', justifyContent: 'space-between', padding: '9px 0', borderBottom: '1px solid var(--border)', fontSize: '14px' }}>
                  <span style={{ color: 'var(--text-secondary)', fontWeight: 500 }}>
                    Seat {s.seat?.rowLetter}{s.seat?.seatNo}
                    <span style={{ fontSize: '11px', marginLeft: '6px', color: 'var(--text-muted)' }}>({s.seat?.seatType})</span>
                  </span>
                  <span style={{ fontWeight: 700 }}>Ōé╣{parseFloat(s.price).toFixed(2)}</span>
                </div>
              ))}
              <div style={{ display: 'flex', justifyContent: 'space-between', padding: '9px 0', borderBottom: '1px solid var(--border)', fontSize: '14px' }}>
                <span style={{ color: 'var(--text-muted)' }}>Subtotal</span>
                <span>Ōé╣{subtotal.toFixed(2)}</span>
              </div>
              {effectiveDiscountPct > 0 && (
                <div style={{ display: 'flex', justifyContent: 'space-between', padding: '9px 0', borderBottom: '1px solid var(--border)', fontSize: '14px' }}>
                  <span style={{ color: 'var(--green)', fontWeight: 600 }}>
                    Discount ({Math.round(effectiveDiscountPct * 100)}% {isLoyaltyUsed ? 'ŌĆö Loyalty Offer ­¤ī¤' : `ŌĆö Code: ${promoCode.toUpperCase()}`})
                  </span>
                  <span style={{ color: 'var(--green)', fontWeight: 700 }}>-Ōé╣{discountAmt.toFixed(2)}</span>
                </div>
              )}
              <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '14px', paddingTop: '4px' }}>
                <span style={{ fontWeight: 700, fontSize: '15px' }}>Total</span>
                <span style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem', fontWeight: 400, color: 'var(--accent)' }}>Ōé╣{total.toFixed(2)}</span>
              </div>
            </div>

            {/* Promo code */}
            <div className="card" style={{ padding: '20px 28px', marginBottom: '16px' }}>
              <h4 style={{ fontFamily: 'var(--font-display)', fontSize: '1.1rem', fontWeight: 400, marginBottom: '14px' }}>
                ­¤ÅĘ Have a Promo Code?
              </h4>
              <div style={{ display: 'flex', gap: '8px' }}>
                <input
                  className="form-input"
                  placeholder="Enter code e.g. SHOW10"
                  value={promoCode}
                  onChange={(e) => { setPromoCode(e.target.value.toUpperCase()); setPromoApplied(false); setPromoError(''); setPromoDiscount(0); }}
                  disabled={promoApplied}
                  style={{ flex: 1, textTransform: 'uppercase', fontFamily: 'var(--font-mono)', fontWeight: 700, letterSpacing: '1px',
                    borderColor: promoApplied ? 'var(--green)' : promoError ? 'var(--accent)' : '' }}
                />
                {promoApplied ? (
                  <button className="btn btn-secondary btn-sm" onClick={() => { setPromoApplied(false); setPromoDiscount(0); setPromoCode(''); setPromoError(''); }}>
                    Remove
                  </button>
                ) : (
                  <button className="btn btn-primary btn-sm" onClick={handleValidateCode} disabled={validatingCode || !promoCode.trim()}>
                    {validatingCode ? '...' : 'Apply'}
                  </button>
                )}
              </div>
              {promoError && <div style={{ marginTop: '8px', fontSize: '12px', color: 'var(--accent)', fontWeight: 600 }}>ŌÜĀ’ĖÅ {promoError}</div>}
              {promoApplied && <div style={{ marginTop: '8px', fontSize: '12px', color: 'var(--green)', fontWeight: 600 }}>Ō£ģ {Math.round(promoDiscount * 100)}% discount applied!</div>}
              <div style={{ marginTop: '10px', fontSize: '11px', color: 'var(--text-muted)' }}>
                Available codes: <code>SHOW10</code> ┬Ę <code>SHOW20</code> ┬Ę <code>FEST15</code>
              </div>
            </div>

            {/* Payment method */}
            <div className="card" style={{ padding: '28px' }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.4rem', fontWeight: 400, marginBottom: '20px' }}>Payment Method</h3>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginBottom: '24px' }}>
                {PAYMENT_METHODS.map((m) => (
                  <button key={m} onClick={() => setPayMethod(m)}
                    style={{ padding: '14px', borderRadius: '10px', border: '1.5px solid', cursor: 'pointer', fontWeight: 700, fontSize: '14px', transition: 'var(--transition)', fontFamily: 'var(--font-body)',
                      borderColor: payMethod === m ? 'var(--accent)' : 'var(--border)',
                      background:  payMethod === m ? 'var(--accent-dim)' : 'var(--bg-card)',
                      color:       payMethod === m ? 'var(--accent)' : 'var(--text-secondary)' }}>
                    <div style={{ fontSize: '22px', marginBottom: '4px' }}>{PM_ICONS[m]}</div>
                    {m}
                  </button>
                ))}
              </div>
              <button onClick={handleConfirmBooking} disabled={processing} className="btn btn-primary btn-full btn-lg">
                {processing ? 'ŌÅ│ Processing...' : `Pay Ōé╣${total.toFixed(2)}`}
              </button>
            </div>
          </div>
        )}

        {/* ŌöĆŌöĆ Step 1: Seat Map ŌöĆŌöĆ */}
        {step === 1 && (
          <>
            {/* Legend */}
            <div style={{ display: 'flex', gap: '20px', marginBottom: '16px', flexWrap: 'wrap', alignItems: 'center' }}>
              <div style={{ display: 'flex', gap: '16px' }}>
                {[['Available','white','var(--border)'],['Selected','var(--accent)','var(--accent)']].map(([label, bg, border]) => (
                  <div key={label} style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '12px', color: 'var(--text-secondary)', fontWeight: 500 }}>
                    <div style={{ width: 18, height: 16, background: bg, border: `2px solid ${border}`, borderRadius: '3px 3px 1px 1px' }} />
                    {label}
                  </div>
                ))}
              </div>
              <div style={{ marginLeft: 'auto', display: 'flex', gap: '14px' }}>
                {Object.entries(SEAT_COLOR).map(([type, color]) => (
                  <span key={type} style={{ fontSize: '12px', color, fontWeight: 600, display: 'flex', alignItems: 'center', gap: '4px' }}>
                    <span style={{ width: 8, height: 8, background: color, borderRadius: '50%', display: 'inline-block' }} />
                    {type}
                  </span>
                ))}
              </div>
            </div>

            {/* Screen */}
            <div style={{ textAlign: 'center', marginBottom: '20px', padding: '8px 24px', background: 'linear-gradient(to bottom,#e5e1d8,#f0ece4)', borderRadius: '6px', border: '1.5px solid var(--border)', fontSize: '11px', color: 'var(--text-muted)', letterSpacing: '6px', textTransform: 'uppercase', fontWeight: 600 }}>
              SCREEN
            </div>

            {/* Seat grid */}
            <div className="card" style={{ padding: '24px', overflowX: 'auto', marginBottom: '16px' }}>
              {availableSeats.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '40px', color: 'var(--text-muted)' }}>
                  <div style={{ fontSize: '40px', marginBottom: '12px' }}>­¤śö</div>
                  <div style={{ fontWeight: 600 }}>No seats available</div>
                </div>
              ) : Object.entries(rows).sort().map(([row, seats]) => (
                <div key={row} style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                  <span style={{ width: '22px', fontSize: '12px', color: 'var(--text-muted)', fontFamily: 'var(--font-mono)', textAlign: 'center', flexShrink: 0, fontWeight: 700 }}>{row}</span>
                  <div style={{ display: 'flex', gap: '5px', flexWrap: 'wrap' }}>
                    {[...seats].sort((a,b) => (a.seat?.seatNo||0)-(b.seat?.seatNo||0)).map((ss) => {
                      const isSelected = !!selected.find((s) => s.seatSlotId === ss.seatSlotId);
                      const c = SEAT_COLOR[ss.seat?.seatType] || '#6b7280';
                      return (
                        <button key={ss.seatSlotId} onClick={() => toggleSeat(ss)}
                          title={`${ss.seat?.rowLetter||row}${ss.seat?.seatNo} ┬Ę ${ss.seat?.seatType} ┬Ę Ōé╣${ss.price}`}
                          style={{ width: '38px', height: '34px', borderRadius: '6px 6px 2px 2px', cursor: 'pointer', transition: 'var(--transition)', fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 700,
                            border:     isSelected ? '2px solid var(--accent)' : `2px solid ${c}55`,
                            background: isSelected ? 'var(--accent)'           : `${c}18`,
                            color:      isSelected ? 'white'                   : c,
                            transform:  isSelected ? 'scale(1.1)'              : 'scale(1)' }}>
                          {ss.seat?.seatNo}
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>

            {/* Sticky bar */}
            {selected.length > 0 && (
              <div style={{ position: 'sticky', bottom: '16px', background: 'white', borderRadius: '14px', border: '2px solid var(--accent)', padding: '16px 24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '16px', flexWrap: 'wrap', boxShadow: '0 8px 32px rgba(224,92,42,0.2)' }}>
                <div>
                  <div style={{ fontSize: '13px', color: 'var(--text-secondary)', marginBottom: '4px', fontWeight: 500 }}>
                    {selected.length} seat{selected.length>1?'s':''}: <strong>{selected.map((s)=>`${s.seat?.rowLetter||''}${s.seat?.seatNo||''}`).join(', ')}</strong>
                  </div>
                  <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.6rem', fontWeight: 400, color: 'var(--accent)' }}>
                    Ōé╣{subtotal.toFixed(2)}
                  </div>
                  {loyaltyDiscount > 0 && (
                    <div style={{ fontSize: '12px', color: 'var(--green)', fontWeight: 600, marginTop: '2px' }}>
                      ­¤ī¤ Loyalty offer available ŌĆö {Math.round(loyaltyDiscount*100)}% off at payment!
                    </div>
                  )}
                </div>
                <button onClick={() => setStep(2)} className="btn btn-primary btn-lg">Proceed to Payment ŌåÆ</button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

const InfoRow = ({ label, value, mono, last }) => (
  <div style={{ display: 'flex', justifyContent: 'space-between', padding: '8px 0', borderBottom: last ? 'none' : '1px solid var(--border)', fontSize: '13px' }}>
    <span style={{ color: 'var(--text-muted)', fontWeight: 600 }}>{label}</span>
    <span style={{ fontFamily: mono ? 'var(--font-mono)' : 'var(--font-body)', fontWeight: 700, color: 'var(--text-primary)' }}>{value}</span>
  </div>
);

export default BookingPage;
